-- ============================================================================
-- 064: بذرة جدول Taxonomy من SUB_CATEGORIES (مرآة الكود وقت النقل) — 117 تخصص
-- ============================================================================
on conflict (sector, sub_key) do update set
  name_ar=excluded.name_ar, name_en=excluded.name_en, name_ur=excluded.name_ur,
  icon=excluded.icon, grp=excluded.grp, keywords=excluded.keywords;